 namespace Contoso.Orders;

 [TestClass]
 public sealed class OrderServiceTests
 {
     private OrderService _sut = null!;

     [TestInitialize]
     public void Setup()
     {
         _sut = new OrderService();
     }

     // ---------------------------------------------------------------
     // CreateOrder — happy path
     // ---------------------------------------------------------------

     [TestMethod]
     public void CreateOrder_SingleItem_ReturnsOrderWithCorrectTotal()
     {
         // Arrange
         var items = new List<OrderItem>
         {
             new() { ProductName = "Widget", Price = 9.99m, Quantity = 3 }
         };

         // Act
         var order = _sut.CreateOrder("cust-1", items);

         // Assert
         Assert.AreEqual(29.97m, order.Total);
         Assert.AreEqual("cust-1", order.CustomerId);
         Assert.AreSame(items, order.Items);
     }

     [TestMethod]
     public void CreateOrder_MultipleItems_ReturnsSumOfPriceTimesQuantity()
     {
         // Arrange
         var items = new List<OrderItem>
         {
             new() { ProductName = "Alpha", Price = 10.00m, Quantity = 2 },
             new() { ProductName = "Beta",  Price = 5.50m,  Quantity = 4 },
             new() { ProductName = "Gamma", Price = 1.25m,  Quantity = 8 }
         };

         // Act
         var order = _sut.CreateOrder("cust-2", items);

         // Assert — 20.00 + 22.00 + 10.00 = 52.00
         Assert.AreEqual(52.00m, order.Total);
     }

     [TestMethod]
     public void CreateOrder_ValidInput_ReturnsOrderWithNonEmptyId()
     {
         // Arrange
         var items = new List<OrderItem>
         {
             new() { ProductName = "Gadget", Price = 15.00m, Quantity = 1 }
         };

         // Act
         var order = _sut.CreateOrder("cust-3", items);

         // Assert
         Assert.IsFalse(string.IsNullOrWhiteSpace(order.Id));
         Assert.IsTrue(Guid.TryParse(order.Id, out _), "Id should be a valid GUID string.");
     }

     [TestMethod]
     public void CreateOrder_ValidInput_SetsCreatedAtToRecentUtcTime()
     {
         // Arrange
         var before = DateTime.UtcNow;
         var items = new List<OrderItem>
         {
             new() { ProductName = "Clock", Price = 25.00m, Quantity = 1 }
         };

         // Act
         var order = _sut.CreateOrder("cust-4", items);
         var after = DateTime.UtcNow;

         // Assert
         Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
             $"CreatedAt {order.CreatedAt:O} should be between {before:O} and {after:O}.");
     }

     [TestMethod]
     public void CreateOrder_ValidInput_StoresOrderInternally()
     {
         // Arrange
         var items = new List<OrderItem>
         {
             new() { ProductName = "Stored", Price = 7.00m, Quantity = 1 }
         };

         // Act
         var created = _sut.CreateOrder("cust-5", items);
         var retrieved = _sut.GetOrder(created.Id);

         // Assert
         Assert.IsNotNull(retrieved);
         Assert.AreSame(created, retrieved);
     }

     // ---------------------------------------------------------------
     // CreateOrder — error cases
     // ---------------------------------------------------------------

     [TestMethod]
     public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
     {
         // Arrange
         var items = new List<OrderItem>
         {
             new() { ProductName = "X", Price = 1m, Quantity = 1 }
         };

         // Act & Assert
         var ex = Assert.ThrowsExactly<ArgumentNullException>(
             () => _sut.CreateOrder(null!, items));
         Assert.AreEqual("customerId", ex.ParamName);
     }

     [TestMethod]
     public void CreateOrder_NullItems_ThrowsArgumentNullException()
     {
         // Act & Assert
         var ex = Assert.ThrowsExactly<ArgumentNullException>(
             () => _sut.CreateOrder("cust-err", null!));
         Assert.AreEqual("items", ex.ParamName);
     }

     [TestMethod]
     public void CreateOrder_EmptyItemsList_ThrowsInvalidOperationException()
     {
         // Arrange
         var items = new List<OrderItem>();

         // Act & Assert
         var ex = Assert.ThrowsExactly<InvalidOperationException>(
             () => _sut.CreateOrder("cust-err", items));
         StringAssert.Contains(ex.Message, "no items");
     }

     // ---------------------------------------------------------------
     // CreateOrder — parameterized total calculation
     // ---------------------------------------------------------------

     [TestMethod]
     [DataRow(1.00, 1, 1.00, DisplayName = "1 × $1.00 = $1.00")]
     [DataRow(5.50, 3, 16.50, DisplayName = "3 × $5.50 = $16.50")]
     [DataRow(0.01, 100, 1.00, DisplayName = "100 × $0.01 = $1.00")]
     [DataRow(99.99, 1, 99.99, DisplayName = "1 × $99.99 = $99.99")]
     public void CreateOrder_SingleItemVariousPricesAndQuantities_CorrectTotal(
         double price, int quantity, double expectedTotal)
     {
         // Arrange
         var items = new List<OrderItem>
         {
             new() { ProductName = "Item", Price = (decimal)price, Quantity = quantity }
         };

         // Act
         var order = _sut.CreateOrder("cust-param", items);

         // Assert
         Assert.AreEqual((decimal)expectedTotal, order.Total);
     }

     // ---------------------------------------------------------------
     // GetOrder
     // ---------------------------------------------------------------

     [TestMethod]
     public void GetOrder_ExistingOrderId_ReturnsMatchingOrder()
     {
         // Arrange
         var items = new List<OrderItem>
         {
             new() { ProductName = "Found", Price = 12.00m, Quantity = 1 }
         };
         var created = _sut.CreateOrder("cust-10", items);

         // Act
         var result = _sut.GetOrder(created.Id);

         // Assert
         Assert.IsNotNull(result);
         Assert.AreEqual(created.Id, result.Id);
         Assert.AreEqual(12.00m, result.Total);
     }

     [TestMethod]
     public void GetOrder_NonExistentId_ReturnsNull()
     {
         // Arrange — add an order so list is non-empty
         var items = new List<OrderItem>
         {
             new() { ProductName = "Decoy", Price = 1m, Quantity = 1 }
         };
         _sut.CreateOrder("cust-11", items);

         // Act
         var result = _sut.GetOrder("non-existent-id");

         // Assert
         Assert.IsNull(result);
     }

     [TestMethod]
     public void GetOrder_EmptyService_ReturnsNull()
     {
         // Act — no orders have been created
         var result = _sut.GetOrder("any-id");

         // Assert
         Assert.IsNull(result);
     }

     // ---------------------------------------------------------------
     // GetOrdersByCustomer
     // ---------------------------------------------------------------

     [TestMethod]
     public void GetOrdersByCustomer_CustomerWithOrders_ReturnsMatchingOrders()
     {
         // Arrange
         var items = new List<OrderItem>
         {
             new() { ProductName = "A", Price = 5m, Quantity = 1 }
         };
         _sut.CreateOrder("cust-20", items);
         _sut.CreateOrder("cust-20", items);

         // Act
         var result = _sut.GetOrdersByCustomer("cust-20");

         // Assert
         Assert.AreEqual(2, result.Count);
         Assert.IsTrue(result.All(o => o.CustomerId == "cust-20"));
     }

     [TestMethod]
     public void GetOrdersByCustomer_NoMatchingCustomer_ReturnsEmptyList()
     {
         // Arrange
         var items = new List<OrderItem>
         {
             new() { ProductName = "B", Price = 3m, Quantity = 1 }
         };
         _sut.CreateOrder("cust-30", items);

         // Act
         var result = _sut.GetOrdersByCustomer("unknown-customer");

         // Assert
         Assert.AreEqual(0, result.Count);
     }

     [TestMethod]
     public void GetOrdersByCustomer_MultipleCustomers_FiltersCorrectly()
     {
         // Arrange
         var items = new List<OrderItem>
         {
             new() { ProductName = "C", Price = 2m, Quantity = 1 }
         };
         _sut.CreateOrder("alice", items);
         _sut.CreateOrder("bob", items);
         _sut.CreateOrder("alice", items);
         _sut.CreateOrder("bob", items);
         _sut.CreateOrder("alice", items);

         // Act
         var aliceOrders = _sut.GetOrdersByCustomer("alice");
         var bobOrders = _sut.GetOrdersByCustomer("bob");

         // Assert
         Assert.AreEqual(3, aliceOrders.Count);
         Assert.AreEqual(2, bobOrders.Count);
         Assert.IsTrue(aliceOrders.All(o => o.CustomerId == "alice"));
         Assert.IsTrue(bobOrders.All(o => o.CustomerId == "bob"));
     }

     [TestMethod]
     public void GetOrdersByCustomer_EmptyService_ReturnsEmptyList()
     {
         // Act — no orders created
         var result = _sut.GetOrdersByCustomer("anyone");

         // Assert
         Assert.AreEqual(0, result.Count);
     }

     // ---------------------------------------------------------------
     // CreateOrder — unique IDs
     // ---------------------------------------------------------------

     [TestMethod]
     public void CreateOrder_CalledMultipleTimes_GeneratesUniqueIds()
     {
         // Arrange
         var items = new List<OrderItem>
         {
             new() { ProductName = "Unique", Price = 1m, Quantity = 1 }
         };

         // Act
         var order1 = _sut.CreateOrder("cust-u", items);
         var order2 = _sut.CreateOrder("cust-u", items);
         var order3 = _sut.CreateOrder("cust-u", items);

         // Assert
         CollectionAssert.AllItemsAreUnique(
             new[] { order1.Id, order2.Id, order3.Id });
     }
 }
